import {
  clampBsTime,
  formatHourWheelLabel,
  formatMinuteWheelLabel,
  formatPeriodLabel,
  formatBsTime,
  formatTimeDigit,
  from12Hour,
  getDefaultBsTime,
  getHourOptions,
  getMinuteOptions,
  getPeriodOptions,
  to12Hour,
} from '@/lib/bs-time-picker/time'
import type { BsLocale, BsPeriod, BsTime } from '@/lib/bs-time-picker/time/types'

export {
  clampBsTime,
  formatTimeDigit,
  getDefaultBsTime,
  getHourOptions,
  getMinuteOptions,
  getPeriodOptions,
  to12Hour,
  from12Hour,
}

export function formatBsTimeWheelLabel(
  time: BsTime,
  locale: BsLocale,
  is24Hour: boolean,
): string {
  return formatBsTime(time, locale, is24Hour)
}

export function formatHourOption(
  hour: number,
  locale: BsLocale,
  is24Hour: boolean,
): string {
  return formatHourWheelLabel(hour, locale, is24Hour)
}

export function formatMinuteOption(minute: number, locale: BsLocale): string {
  return formatMinuteWheelLabel(minute, locale)
}

export function formatPeriodOption(period: BsPeriod, locale: BsLocale): string {
  return formatPeriodLabel(period, locale)
}

export function resolveWheelHour(
  displayHour: number,
  period: BsPeriod,
  is24Hour: boolean,
): number {
  if (is24Hour) return displayHour
  return from12Hour(displayHour, period)
}

export function resolveDisplayHour(hour24: number, is24Hour: boolean): number {
  if (is24Hour) return hour24
  return to12Hour(hour24).hour
}

export function resolveDisplayPeriod(hour24: number, is24Hour: boolean): BsPeriod {
  if (is24Hour) return 'am'
  return to12Hour(hour24).period
}

import type { BsDate, BsLocale } from '../../bs-day-picker/types'

export type { BsLocale }

export type BsTime = {
  hour: number
  minute: number
}

export type BsDateTime = BsDate & BsTime

export type BsPeriod = 'am' | 'pm'

export function bsTimeKey(time: BsTime): string {
  return `${time.hour}:${time.minute}`
}

export function parseBsTimeKey(key: string): BsTime | null {
  const match = key.match(/^(\d+):(\d+)$/)
  if (!match) return null
  return {
    hour: Number(match[1]),
    minute: Number(match[2]),
  }
}

export function bsTimesEqual(a?: BsTime, b?: BsTime): boolean {
  if (!a || !b) return false
  return a.hour === b.hour && a.minute === b.minute
}

import type { BsPeriod, BsTime } from './types'

export function clampBsTime(time: BsTime): BsTime {
  const hour = Math.min(23, Math.max(0, Math.round(time.hour)))
  const minute = Math.min(59, Math.max(0, Math.round(time.minute)))
  return { hour, minute }
}

export function getDefaultBsTime(): BsTime {
  const now = new Date()
  return { hour: now.getHours(), minute: now.getMinutes() }
}

export function getHourOptions(is24Hour: boolean): number[] {
  if (is24Hour) {
    return Array.from({ length: 24 }, (_, index) => index)
  }
  return Array.from({ length: 12 }, (_, index) => index + 1)
}

export function getMinuteOptions(): number[] {
  return Array.from({ length: 60 }, (_, index) => index)
}

export function getPeriodOptions(): BsPeriod[] {
  return ['am', 'pm']
}

export function to12Hour(hour24: number): { hour: number; period: BsPeriod } {
  const normalized = ((hour24 % 24) + 24) % 24
  const period: BsPeriod = normalized >= 12 ? 'pm' : 'am'
  const hour12 = normalized % 12 || 12
  return { hour: hour12, period }
}

export function from12Hour(hour12: number, period: BsPeriod): number {
  const normalized = ((hour12 % 12) + 12) % 12 || 12
  if (period === 'am') {
    return normalized === 12 ? 0 : normalized
  }
  return normalized === 12 ? 12 : normalized + 12
}

export function bsTimeToDate(time: BsTime, base = new Date()): Date {
  const date = new Date(base)
  date.setHours(time.hour, time.minute, 0, 0)
  return date
}

export function dateToBsTime(date: Date): BsTime {
  return {
    hour: date.getHours(),
    minute: date.getMinutes(),
  }
}

import { pad2, toNepaliDigit } from '../../bs-day-picker/constants'
import type { BsLocale } from '../../bs-day-picker/types'
import { to12Hour } from './helpers'
import type { BsTime } from './types'

export function formatTimeDigit(value: number, locale: BsLocale): string {
  return pad2(value, locale)
}

export function formatBsTime(
  time: BsTime,
  locale: BsLocale = 'en',
  is24Hour = false,
): string {
  if (is24Hour) {
    return `${formatTimeDigit(time.hour, locale)}:${formatTimeDigit(time.minute, locale)}`
  }

  const { hour, period } = to12Hour(time.hour)
  const periodLabel =
    locale === 'ne'
      ? period === 'am'
        ? 'पूर्वाह्न'
        : 'अपराह्न'
      : period.toUpperCase()
  return `${formatTimeDigit(hour, locale)}:${formatTimeDigit(time.minute, locale)} ${periodLabel}`
}

export function formatBsTimeWheelLabel(
  time: BsTime,
  locale: BsLocale,
  is24Hour: boolean,
): string {
  return formatBsTime(time, locale, is24Hour)
}

export function formatHourWheelLabel(
  hour: number,
  locale: BsLocale,
  is24Hour: boolean,
): string {
  if (is24Hour) return formatTimeDigit(hour, locale)
  return formatTimeDigit(hour, locale)
}

export function formatMinuteWheelLabel(minute: number, locale: BsLocale): string {
  return formatTimeDigit(minute, locale)
}

export function formatPeriodLabel(period: 'am' | 'pm', locale: BsLocale): string {
  if (locale === 'ne') {
    return period === 'am' ? 'एम' : 'पिम'
  }
  return period.toUpperCase()
}

import { getDayAdDate } from '../../bs-day-picker/calendar-grid'
import { formatBsDateLongWithWeekday } from '../../bs-day-picker/formatters'
import { getCurrentBsDate } from '../../bs-day-picker/navigation'
import type { BsDate } from '../../bs-day-picker/types'
import { clampBsTime, getDefaultBsTime } from './helpers'
import { formatBsTime } from './formatters'
import type { BsDateTime, BsLocale, BsTime } from './types'

export function clampBsDateTime(value: BsDateTime): BsDateTime {
  return {
    ...value,
    ...clampBsTime(value),
  }
}

export function getDefaultBsDateTime(): BsDateTime {
  const date = getCurrentBsDate()
  const time = getDefaultBsTime()
  return { ...date, ...time }
}

export function mergeBsDateTime(date: BsDate, time: BsTime): BsDateTime {
  return clampBsDateTime({ ...date, ...time })
}

export function splitBsDateTime(value: BsDateTime): { date: BsDate; time: BsTime } {
  return {
    date: { year: value.year, month: value.month, day: value.day },
    time: { hour: value.hour, minute: value.minute },
  }
}

export function formatBsDateTime(
  value: BsDateTime,
  locale: BsLocale = 'en',
  is24Hour = false,
): string {
  const dateLabel = formatBsDateLongWithWeekday(value, locale)
  const timeLabel = formatBsTime(value, locale, is24Hour)
  return `${dateLabel}, ${timeLabel}`
}

/** Map BS datetime to AD `Date` using calendar data (Asia/Kathmandu local fields). */
export function toAdDate(value: BsDateTime): Date | null {
  const adDate = getDayAdDate(value)
  if (!adDate) return null

  const [year, month, day] = adDate.split('-').map(Number)
  if (year == null || month == null || day == null) return null

  const date = new Date(year, month - 1, day, value.hour, value.minute, 0, 0)
  return date
}

import { Text } from '@/components/ui/text'
import { cn } from '@/lib/utils'
import * as React from 'react'
import {
  FlatList,
  Platform,
  type ListRenderItemInfo,
  type NativeScrollEvent,
  type NativeSyntheticEvent,
  Pressable,
  View,
} from 'react-native'

const ITEM_HEIGHT = Platform.OS === 'ios' ? 44 : 48
const VISIBLE_COUNT = 5
export const BS_WHEEL_HEIGHT = ITEM_HEIGHT * VISIBLE_COUNT
const EDGE_PADDING = ITEM_HEIGHT * Math.floor(VISIBLE_COUNT / 2)
const DEFAULT_LOOP_REPEATS = 51

type BsWheelColumnProps<T extends string | number> = {
  items: readonly T[]
  selected: T
  onSelect: (value: T) => void
  formatLabel: (value: T) => string
  className?: string
  showOverlay?: boolean
  /** Repeat items and recenter while scrolling for a native infinite wheel feel. */
  loop?: boolean
  loopRepeats?: number
  /** Avoid O(n) lookup when the item list is large (e.g. chronological dates). */
  selectedIndex?: number
}

function normalizeIndex(index: number, length: number): number {
  if (length === 0) return 0
  return ((index % length) + length) % length
}

export function BsWheelColumn<T extends string | number>({
  items,
  selected,
  onSelect,
  formatLabel,
  className,
  showOverlay = true,
  loop = false,
  loopRepeats = DEFAULT_LOOP_REPEATS,
  selectedIndex: selectedIndexProp,
}: BsWheelColumnProps<T>) {
  const listRef = React.useRef<FlatList<T>>(null)
  const isRecenteringRef = React.useRef(false)
  const selectedIndex = Math.max(
    0,
    selectedIndexProp ?? items.indexOf(selected),
  )
  const middleOffset =
    loop && items.length > 0
      ? Math.floor(loopRepeats / 2) * items.length
      : 0

  const data = React.useMemo(() => {
    if (!loop || items.length === 0) return [...items]
    return Array.from(
      { length: items.length * loopRepeats },
      (_, index) => items[normalizeIndex(index, items.length)]!,
    )
  }, [items, loop, loopRepeats])

  const indexForSelected = React.useCallback(
    (index: number) => (loop ? middleOffset + index : index),
    [loop, middleOffset],
  )

  const [focusedIndex, setFocusedIndex] = React.useState(() =>
    indexForSelected(selectedIndex),
  )

  const scrollToIndex = React.useCallback(
    (index: number, animated = false) => {
      if (index < 0 || index >= data.length) return
      listRef.current?.scrollToOffset({
        offset: index * ITEM_HEIGHT,
        animated,
      })
      setFocusedIndex(index)
    },
    [data.length],
  )

  const recenterIfNeeded = React.useCallback(
    (index: number) => {
      if (!loop || items.length === 0) return index

      const edgeBuffer = items.length * 2
      if (index >= edgeBuffer && index < data.length - edgeBuffer) {
        return index
      }

      const normalizedIndex = normalizeIndex(index, items.length)
      const targetIndex = middleOffset + normalizedIndex
      isRecenteringRef.current = true
      listRef.current?.scrollToOffset({
        offset: targetIndex * ITEM_HEIGHT,
        animated: false,
      })
      setFocusedIndex(targetIndex)
      requestAnimationFrame(() => {
        isRecenteringRef.current = false
      })
      return targetIndex
    },
    [data.length, items.length, loop, middleOffset],
  )

  React.useEffect(() => {
    const targetIndex = indexForSelected(selectedIndex)
    // Scroll only — avoid setFocusedIndex here (react-hooks/set-state-in-effect).
    if (targetIndex < 0 || targetIndex >= data.length) return
    listRef.current?.scrollToOffset({
      offset: targetIndex * ITEM_HEIGHT,
      animated: false,
    })
  }, [data.length, indexForSelected, selectedIndex])

  const commitIndex = React.useCallback(
    (index: number) => {
      const boundedIndex = Math.min(
        data.length - 1,
        Math.max(0, Math.round(index)),
      )
      const settledIndex = recenterIfNeeded(boundedIndex)
      const normalizedIndex = loop
        ? normalizeIndex(settledIndex, items.length)
        : settledIndex
      const next = items[normalizedIndex]
      if (next !== undefined && next !== selected) {
        onSelect(next)
      }
    },
    [data.length, items, loop, onSelect, recenterIfNeeded, selected],
  )

  const handleScroll = (event: NativeSyntheticEvent<NativeScrollEvent>) => {
    if (isRecenteringRef.current) return

    const index = Math.min(
      data.length - 1,
      Math.max(0, Math.round(event.nativeEvent.contentOffset.y / ITEM_HEIGHT)),
    )

    if (index !== focusedIndex) {
      setFocusedIndex(index)
    }
  }

  const handleMomentumEnd = (offsetY: number) => {
    commitIndex(offsetY / ITEM_HEIGHT)
  }

  const renderItem = ({ item, index }: ListRenderItemInfo<T>) => {
    const isFocused = index === focusedIndex
    return (
      <Pressable
        className="w-full items-center justify-center px-3"
        style={{ height: ITEM_HEIGHT }}
        onPress={() => {
          scrollToIndex(index, true)
          const normalizedIndex = loop
            ? normalizeIndex(index, items.length)
            : index
          const next = items[normalizedIndex]
          if (next !== undefined) {
            onSelect(next)
          }
        }}
      >
        <Text
          className={cn(
            'w-full text-center text-[17px] leading-[22px]',
            isFocused
              ? 'font-semibold text-foreground'
              : 'font-normal text-muted-foreground/70',
          )}
          numberOfLines={1}
          adjustsFontSizeToFit
          minimumFontScale={0.85}
        >
          {formatLabel(item)}
        </Text>
      </Pressable>
    )
  }

  return (
    <View
      className={cn('relative flex-1', className)}
      style={{ height: BS_WHEEL_HEIGHT }}
    >
      {showOverlay ? (
        <View
          pointerEvents="none"
          className="absolute inset-x-3 top-1/2 z-0 -mt-[22px] h-11 rounded-[10px] bg-[#787880]/20"
        />
      ) : null}
      <FlatList
        ref={listRef}
        data={data}
        style={{ zIndex: 1 }}
        initialScrollIndex={
          data.length > 0 ? Math.min(focusedIndex, data.length - 1) : undefined
        }
        keyExtractor={(item, index) => `${String(item)}-${index}`}
        renderItem={renderItem}
        showsVerticalScrollIndicator={false}
        snapToInterval={ITEM_HEIGHT}
        decelerationRate="fast"
        getItemLayout={(_, index) => ({
          length: ITEM_HEIGHT,
          offset: ITEM_HEIGHT * index,
          index,
        })}
        contentContainerStyle={{ paddingVertical: EDGE_PADDING }}
        onScroll={handleScroll}
        scrollEventThrottle={16}
        onMomentumScrollEnd={(event) =>
          handleMomentumEnd(event.nativeEvent.contentOffset.y)
        }
        onScrollEndDrag={(event) => {
          if (event.nativeEvent.velocity?.y === 0) {
            handleMomentumEnd(event.nativeEvent.contentOffset.y)
          }
        }}
      />
    </View>
  )
}

import {
  clampBsTime,
  formatMinuteOption,
  formatPeriodOption,
  formatTimeDigit,
  resolveDisplayHour,
  resolveDisplayPeriod,
  to12Hour,
  from12Hour,
} from '@/lib/bs-time-picker'
import type { BsLocale, BsPeriod, BsTime } from '@/lib/bs-time-picker/time/types'
import { cn } from '@/lib/utils'
import * as React from 'react'
import { Modal, Pressable, View } from 'react-native'
import Svg, { Circle, Line } from 'react-native-svg'
import { Text } from '@/components/ui/text'

const CLOCK_SIZE = 256
const CLOCK_RADIUS = 98
const NODE_SIZE = 40
const CENTER = CLOCK_SIZE / 2
/** Reach the center of dial labels (Material hand length). */
const HAND_RADIUS = CLOCK_RADIUS - NODE_SIZE / 2
const HAND_COLOR = 'hsl(180, 82%, 24%)'

type SelectionMode = 'hour' | 'minute'

type BsTimePickerDialogProps = {
  visible: boolean
  value: BsTime
  locale: BsLocale
  is24Hour?: boolean
  title?: string
  cancelLabel: string
  confirmLabel: string
  onChange: (value: BsTime) => void
  onCancel: () => void
  onConfirm: () => void
}

/** Degrees clockwise from 12 o'clock (Material clock convention). */
function hour12ToClockDegrees(hour12: number): number {
  const normalized = hour12 === 12 ? 0 : hour12
  return normalized * 30
}

function hour24ToClockDegrees(hour24: number): number {
  return (hour24 / 24) * 360
}

function minuteToClockDegrees(minute: number): number {
  return (minute / 60) * 360
}

function positionForClockDegrees(clockDegrees: number, radius: number) {
  const radians = (clockDegrees - 90) * (Math.PI / 180)
  return {
    left: CENTER + radius * Math.cos(radians) - NODE_SIZE / 2,
    top: CENTER + radius * Math.sin(radians) - NODE_SIZE / 2,
  }
}

function getHourDialValues(is24Hour: boolean): number[] {
  return is24Hour
    ? Array.from({ length: 24 }, (_, index) => index)
    : Array.from({ length: 12 }, (_, index) => index + 1)
}

function getMinuteDialValues(): number[] {
  return Array.from({ length: 12 }, (_, index) => index * 5)
}

function hourValueToClockDegrees(hour: number, is24Hour: boolean): number {
  return is24Hour ? hour24ToClockDegrees(hour) : hour12ToClockDegrees(hour)
}

function minuteValueToClockDegrees(minute: number): number {
  return minuteToClockDegrees(minute)
}

function clockPoint(clockDegrees: number, radius: number) {
  const radians = (clockDegrees - 90) * (Math.PI / 180)
  return {
    x: CENTER + radius * Math.cos(radians),
    y: CENTER + radius * Math.sin(radians),
  }
}

type BsTimePickerClockProps = {
  mode: SelectionMode
  value: BsTime
  locale: BsLocale
  is24Hour: boolean
  onSelectHour: (hour: number) => void
  onSelectMinute: (minute: number) => void
}

function ClockHand({ clockDegrees }: { clockDegrees: number }) {
  const end = clockPoint(clockDegrees, HAND_RADIUS)

  return (
    <Svg
      width={CLOCK_SIZE}
      height={CLOCK_SIZE}
      pointerEvents="none"
      style={{ position: 'absolute', left: 0, top: 0, zIndex: 1 }}
    >
      <Line
        x1={CENTER}
        y1={CENTER}
        x2={end.x}
        y2={end.y}
        stroke={HAND_COLOR}
        strokeWidth={2}
        strokeLinecap="round"
      />
      <Circle cx={CENTER} cy={CENTER} r={5} fill={HAND_COLOR} />
    </Svg>
  )
}

function BsTimePickerClock({
  mode,
  value,
  locale,
  is24Hour,
  onSelectHour,
  onSelectMinute,
}: BsTimePickerClockProps) {
  const dialValues =
    mode === 'hour' ? getHourDialValues(is24Hour) : getMinuteDialValues()

  const selectedHour = is24Hour ? value.hour : resolveDisplayHour(value.hour, false)
  const selectedMinute = value.minute

  const handClockDegrees =
    mode === 'hour'
      ? hourValueToClockDegrees(selectedHour, is24Hour)
      : minuteValueToClockDegrees(selectedMinute)

  return (
    <View
      className="relative self-center rounded-full border border-border/70 bg-input"
      style={{ width: CLOCK_SIZE, height: CLOCK_SIZE }}
    >
      <ClockHand clockDegrees={handClockDegrees} />

      {dialValues.map((dialValue) => {
        const clockDegrees =
          mode === 'hour'
            ? hourValueToClockDegrees(dialValue, is24Hour)
            : minuteValueToClockDegrees(dialValue)

        const isSelected =
          mode === 'hour'
            ? dialValue === selectedHour
            : Math.abs(dialValue - selectedMinute) < 3 ||
              (selectedMinute >= 58 && dialValue === 0)

        const position = positionForClockDegrees(clockDegrees, CLOCK_RADIUS)
        const label =
          mode === 'hour'
            ? formatTimeDigit(dialValue, locale)
            : formatMinuteOption(dialValue, locale)

        return (
          <Pressable
            key={`${mode}-${dialValue}`}
            className={cn(
              'absolute z-20 items-center justify-center rounded-full',
              isSelected ? 'bg-primary' : 'bg-transparent',
            )}
            style={{
              left: position.left,
              top: position.top,
              width: NODE_SIZE,
              height: NODE_SIZE,
            }}
            onPress={() => {
              if (mode === 'hour') {
                if (is24Hour) {
                  onSelectHour(dialValue)
                } else {
                  const period = resolveDisplayPeriod(value.hour, false)
                  onSelectHour(from12Hour(dialValue, period))
                }
              } else {
                onSelectMinute(dialValue)
              }
            }}
          >
            <Text
              className={cn(
                'text-sm font-medium',
                isSelected ? 'text-primary-foreground' : 'text-foreground',
              )}
            >
              {label}
            </Text>
          </Pressable>
        )
      })}
    </View>
  )
}

export function BsTimePickerDialog({
  visible,
  value,
  locale,
  is24Hour = false,
  title,
  cancelLabel,
  confirmLabel,
  onChange,
  onCancel,
  onConfirm,
}: BsTimePickerDialogProps) {
  const [selectionMode, setSelectionMode] = React.useState<SelectionMode>('hour')
  const clamped = clampBsTime(value)
  const displayHour = resolveDisplayHour(clamped.hour, is24Hour)
  const displayPeriod = resolveDisplayPeriod(clamped.hour, is24Hour)

  const updateTime = (patch: Partial<BsTime>) => {
    onChange(clampBsTime({ ...clamped, ...patch }))
  }

  const setPeriod = (period: BsPeriod) => {
    const { hour: hour12 } = to12Hour(clamped.hour)
    updateTime({ hour: from12Hour(hour12, period) })
  }

  const handleSelectHour = (hour24: number) => {
    updateTime({ hour: hour24 })
    setSelectionMode('minute')
  }

  if (!visible) return null

  return (
    <Modal visible transparent animationType="fade" onRequestClose={onCancel}>
      <Pressable
        className="flex-1 items-center justify-center bg-black/50 px-5 py-6"
        onPress={onCancel}
      >
        <Pressable
          className="w-full max-w-[360px] overflow-hidden rounded-[28px] bg-background"
          onPress={(event) => event.stopPropagation()}
        >
          {title ? (
            <View className="px-6 pb-2 pt-6">
              <Text className="text-sm font-medium text-muted-foreground">
                {title}
              </Text>
            </View>
          ) : null}

          <View className="flex-row items-center px-6 pb-4 pt-4">
            <View className="flex-1 flex-row items-center gap-2">
              <Pressable
                className={cn(
                  'min-w-[72px] rounded-xl px-3 py-3',
                  selectionMode === 'hour' ? 'bg-primary/15' : 'bg-input',
                )}
                onPress={() => setSelectionMode('hour')}
              >
                <Text className="text-center text-[44px] leading-none text-foreground">
                  {formatTimeDigit(displayHour, locale)}
                </Text>
              </Pressable>

              <Text className="text-[44px] leading-none text-muted-foreground">
                :
              </Text>

              <Pressable
                className={cn(
                  'min-w-[72px] rounded-xl px-3 py-3',
                  selectionMode === 'minute' ? 'bg-primary/15' : 'bg-input',
                )}
                onPress={() => setSelectionMode('minute')}
              >
                <Text className="text-center text-[44px] leading-none text-foreground">
                  {formatMinuteOption(clamped.minute, locale)}
                </Text>
              </Pressable>
            </View>

            {!is24Hour ? (
              <View className="ml-3 overflow-hidden rounded-xl border border-border/60">
                <Pressable
                  className={cn(
                    'min-w-12 items-center px-3 py-2',
                    displayPeriod === 'am' ? 'bg-primary/15' : 'bg-transparent',
                  )}
                  onPress={() => setPeriod('am')}
                >
                  <Text className="text-xs font-semibold uppercase text-foreground">
                    {formatPeriodOption('am', locale)}
                  </Text>
                </Pressable>
                <Pressable
                  className={cn(
                    'min-w-12 items-center px-3 py-2',
                    displayPeriod === 'pm' ? 'bg-primary/15' : 'bg-transparent',
                  )}
                  onPress={() => setPeriod('pm')}
                >
                  <Text className="text-xs font-semibold uppercase text-foreground">
                    {formatPeriodOption('pm', locale)}
                  </Text>
                </Pressable>
              </View>
            ) : null}
          </View>

          <View className="items-center px-4 pb-4 pt-1">
            <BsTimePickerClock
              mode={selectionMode}
              value={clamped}
              locale={locale}
              is24Hour={is24Hour}
              onSelectHour={handleSelectHour}
              onSelectMinute={(minute) => updateTime({ minute })}
            />
          </View>

          <View className="flex-row justify-end px-2 pb-3 pt-1">
            <Pressable
              className="min-h-12 items-center justify-center px-4"
              onPress={onCancel}
            >
              <Text className="text-sm font-semibold uppercase text-primary">
                {cancelLabel}
              </Text>
            </Pressable>
            <Pressable
              className="min-h-12 items-center justify-center px-4"
              onPress={onConfirm}
            >
              <Text className="text-sm font-semibold uppercase text-primary">
                {confirmLabel}
              </Text>
            </Pressable>
          </View>
        </Pressable>
      </Pressable>
    </Modal>
  )
}

